package ra.edu.shoesphere.controller;
import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import ra.edu.shoesphere.model.dto.request.CartItemRequestDTO; import ra.edu.shoesphere.model.dto.response.*; import ra.edu.shoesphere.service.CartService; import java.util.*;
@RestController @RequestMapping("/api/v1/cart") @RequiredArgsConstructor public class CartController { private final CartService service; @GetMapping public ResponseEntity<ApiDataResponse<List<CartItemResponseDTO>>> get(Authentication a){return ResponseEntity.ok(new ApiDataResponse<>(true,"Cart retrieved.",service.get(a.getName()),null,HttpStatus.OK));} @PostMapping("/items") public ResponseEntity<ApiDataResponse<CartItemResponseDTO>> add(Authentication a,@Valid @RequestBody CartItemRequestDTO r){return ResponseEntity.ok(new ApiDataResponse<>(true,"Item added.",service.add(a.getName(),r),null,HttpStatus.OK));} @PutMapping("/items/{id}") public ResponseEntity<ApiDataResponse<CartItemResponseDTO>> update(Authentication a,@PathVariable Long id,@Valid @RequestBody CartItemRequestDTO r){return ResponseEntity.ok(new ApiDataResponse<>(true,"Cart updated.",service.update(a.getName(),id,r.getQuantity()),null,HttpStatus.OK));} @DeleteMapping("/items/{id}") public ResponseEntity<ApiDataResponse<Void>> del(Authentication a,@PathVariable Long id){service.delete(a.getName(),id);return ResponseEntity.ok(new ApiDataResponse<>(true,"Item removed.",null,null,HttpStatus.OK));} }
